#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 1e6+5;
LL T,p[N],cnt,phi[N],res[N];
bool vis[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void init(){
    vis[0]=1,vis[1]=1;
    phi[1]=0,cnt=0;
    for(LL i=2;i<=1000000;i++){
        if(!vis[i])p[++cnt]=i,phi[i]=i-1;
        for(int j=1;j<=cnt&&i*p[j]<=1000000;j++){
            vis[i*p[j]]=1;
            if(i%p[j]==0){phi[i*p[j]]=phi[i]*p[j];break;}
            else phi[i*p[j]]=phi[i]*(p[j]-1);
        }
    }for(LL x=1;x<=1000000;x++)
        for(LL k=1;k*x<=1000000;k++)
            res[x*k]+=(x==1?x:phi[x]*x/2);
    return;
}
int main(){
    T=read();init();
    while(T--){
        LL n=read();
        cout<<res[n]*n<<"\n";
    }
    return 0;
}
